import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import PhoneInput from 'react-phone-input-2';
import 'react-phone-input-2/lib/style.css';
import { isValidPhoneNumber } from 'libphonenumber-js';
import image from '../../static/images/Untitled_design.png';
import axios from 'axios';

function generateCaptcha(length = 5) {
  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789";
  let captcha = "";
  for (let i = 0; i < length; i++) {
    captcha += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return captcha;
}

function Vendor_registration() {
  const [visible, setVisible] = useState(false);
      const [error, setError] = useState(false);
      const [password, setPassword] = useState("");
      const [email, setEmail] = useState("");
      const [name, setName] = useState("")
      const [phno, setPhno] = useState("");
      const [purposes, setPurposes] = useState([]);
      const [purposeInput, setPurposeInput] = useState("");
      const [address, setAddress] = useState("");
      const [captcha, setCaptcha] = useState("");
      const [userCaptcha, setUserCaptcha] = useState("");
      const [captchaError, setCaptchaError] = useState("");
      const [rememberMe, setRememberMe] = useState(false);
      const navigate = useNavigate();

      useEffect(() => {
          setCaptcha(generateCaptcha());
        }, []);
      
        const refreshCaptcha = () => {
          setCaptcha(generateCaptcha());
          setUserCaptcha("");
        };
      
        const validate_email = (email) => {
          const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
          return regex.test(email);
        };
        const validate_password = (psw) => {
          var errors = [];
          var regex1 = /^.{8,16}$/;
          var regex2 = /^(?=.*[a-z])(?=.*[A-Z])(?=.*[^a-zA-Z0-9.,])(?!.*[.,]).+$/;
          if (!regex1.test(psw)) {
            errors.push("The password should contain from 8 to 16 characters.");
          }
          if (!regex2.test(psw)) {
            errors.push(
              "The password must contain atleast one uppercase letter, one lowercase letter and one special character."
            );
          }
          return errors;
        };
      
        const validate = (email, password, phno) => {
          let result = {
            emailValid: true,
            passwordErrors: [],
            phErrors:[],
          };
      
          if (!validate_email(email)) {
            result.emailValid = false;
          }

          if(!isValidPhoneNumber(`+${phno}`)){
            result.phErrors.push('Invalid Phone Number');
          }

          const passwordValidation = validate_password(password);
          if (passwordValidation.length > 0) {
            result.passwordErrors = passwordValidation;
          }
      
          return result;
        };
      
        const handleSubmit = (e) => {
          e.preventDefault();
      
          const result = validate(email, password, phno);
          let isValid = true;
      
          // 1. Email & password validation
          if (!result.emailValid || result.passwordErrors.length > 0 || !result.phErrors) {
            setError(result);
            isValid = false;
          } else {
            setError(false);
          }
      
          // 2. CAPTCHA validation
          if (userCaptcha.trim() !== captcha.trim()) {
            setCaptchaError("CAPTCHA does not match.");
            isValid = false;
          } else {
            setCaptchaError("");
          }
      
          // 3. Hardcoded authentication only if all validations pass
          if (isValid) {
            //Database logic - insert name, ph no., email and password into users table sql
              
               axios.post('http://localhost:5000/api/auth/register', {
    name,
    email,
    password,
    phno,
    address,
    purposes
  })
  .then((response) => {
    console.log(response.data.message);
    // Reset everything
    setEmail("");
    setPassword("");
    setPhno("");
    setUserCaptcha("");
    setCaptcha(generateCaptcha());
    setError(false);
    setCaptchaError("");
    navigate("/");
  })
  .catch((error) => {
    console.error(error.response?.data?.error || "Registration failed");
    setError({ ...error.response?.data });
  });
            }
            };

  return (
    <div>
       <div className="container-fluid px-0">
  <div className="row g-0 min-vh-100">

    {/* LEFT SIDE: Image section (only on md and up) */}
    <div
          className="col-md-6 d-none d-md-block"
          style={{
            backgroundImage: `url(${image})`,
            backgroundSize: "cover",
            backgroundRepeat: "no-repeat",
            backgroundPosition: "center",
          }}
        ></div>

    {/* RIGHT SIDE: Login */}
    <div className="col-12 col-md-6 d-flex flex-column bg-light" >

      {/* LOGIN FORM */}
      <div className="d-flex flex-grow-1 align-items-center justify-content-center px-3 py-5">
        <div className="col-12 col-sm-10 col-md-10 col-lg-9 col-xl-8">
          <div className="p-4 bg-white bg-opacity-75 rounded-4 green-shadow">
            <h3 className="text-center fw-bold mb-4 text-success">Register as Vendor</h3>
            <form onSubmit={handleSubmit}>
              <div className="mb-3">
                <label htmlFor="exampleInputEmail1" className="form-label">
                  Email address
                </label>
                <input
                  type="email"
                  className="form-control"
                  id="exampleInputEmail1"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                />

                {error && error.emailValid === false && (
                  <p style={{ color: "red" }}>Invalid email address.</p>
                )}
              </div>

              <div className="mb-3">
                <label htmlFor="exampleInputPassword1" className="form-label">
                  Password
                </label>
                <div className="input-group">
                  <input
                    type={visible ? "text" : "password"}
                    className="form-control"
                    id="exampleInputPassword1"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                  />
                  <button
                    type="button"
                    className="btn btn-outline-secondary text-success btn-eye-toggle"
                    onClick={() => setVisible((prev) => !prev)}
                    tabIndex={-1}
                  >
                    {visible ? (
                      <svg
                        xmlns="http://www.w3.org/2000/svg"
                        width="16"
                        height="16"
                        fill="currentColor"
                        class="bi bi-eye-slash-fill"
                        viewBox="0 0 16 16"
                        
                      >
                        <path d="m10.79 12.912-1.614-1.615a3.5 3.5 0 0 1-4.474-4.474l-2.06-2.06C.938 6.278 0 8 0 8s3 5.5 8 5.5a7 7 0 0 0 2.79-.588M5.21 3.088A7 7 0 0 1 8 2.5c5 0 8 5.5 8 5.5s-.939 1.721-2.641 3.238l-2.062-2.062a3.5 3.5 0 0 0-4.474-4.474z" />
                        <path d="M5.525 7.646a2.5 2.5 0 0 0 2.829 2.829zm4.95.708-2.829-2.83a2.5 2.5 0 0 1 2.829 2.829zm3.171 6-12-12 .708-.708 12 12z" />
                      </svg>
                    ) : (
                      <svg
                        xmlns="http://www.w3.org/2000/svg"
                        width="16"
                        height="16"
                        fill="currentColor"
                        class="bi bi-eye-fill"
                        viewBox="0 0 16 16"
                    
                      >
                        <path d="M10.5 8a2.5 2.5 0 1 1-5 0 2.5 2.5 0 0 1 5 0" />
                        <path d="M0 8s3-5.5 8-5.5S16 8 16 8s-3 5.5-8 5.5S0 8 0 8m8 3.5a3.5 3.5 0 1 0 0-7 3.5 3.5 0 0 0 0 7" />
                      </svg>
                    )}
                  </button>
                </div>
                {error &&
                  error.passwordErrors &&
                  error.passwordErrors.map((err, index) => (
                    <p key={index} style={{ color: "red" }}>
                      {err}
                    </p>
                  ))}
              </div>

              <div className="mb-3">
                <label htmlFor="exampleInputName1" className="form-label">
                  Name
                </label>
                <input
                  type="text"
                  className="form-control"
                  value={name}
                  id="exampleInputName1"
                  onChange={(e) => setName(e.target.value)}
                />
              </div>

              <div className="mb-3">
                <label htmlFor="exampleInputPh1" className="form-label">
                  Phone Number
                </label>
                <PhoneInput
        country={'in'} // default country
        value={phno}
        onChange={setPhno}
        enableSearch={true} // optional: search countries
          inputStyle={{ width: '100%' }}   
      />

                {error &&
                  error.phErrors &&
                  error.phErrors.map((err, index) => (
                    <p key={index} style={{ color: "red" }}>
                      {err}
                    </p>))}
              </div>

              {/* ADDRESS */} 
              <div className="mb-3"> 
                <label className="form-label">Address</label> 
                <textarea className="form-control" rows="2" value={address} 
                onChange={(e) => setAddress(e.target.value)} placeholder="Enter your shop or business address" ></textarea>
              </div>

              {/* PURPOSE / PRODUCTS PREFERENCE */}
<div className="mb-3">
  <label className="form-label">
    What types of products do you want to sell? (max 4)
  </label>

  <input
    type="text"
    className="form-control"
    placeholder="Type a product and press Enter (e.g. scrap metal, e-waste)"
    value={purposeInput}
    onChange={(e) => setPurposeInput(e.target.value)}
    onKeyDown={(e) => {
      if (e.key === "Enter") {
        e.preventDefault();
        const newItem = purposeInput.trim();
        if (newItem && !purposes.includes(newItem)) {
          if (purposes.length < 4) {
            setPurposes([...purposes, newItem]);
            setPurposeInput("");
          } else {
            alert("You can only add up to 4 preferred products.");
          }
        }
      }
    }}
  />

  {/* Display selected products */}
  <div className="mt-2 d-flex flex-wrap gap-2">
    {purposes.map((item, index) => (
      <div
        key={index}
        className="badge bg-success text-light d-flex align-items-center p-2"
        style={{ fontSize: "0.9rem" }}
      >
        {item}
        <button
          type="button"
          className="btn-close btn-close-white ms-2"
          aria-label="Remove"
          onClick={() => {
            setPurposes(purposes.filter((_, i) => i !== index));
          }}
          style={{ fontSize: "0.6rem" }}
        ></button>
      </div>
    ))}
  </div>
</div>


              <div className="mb-3">
                <label className="form-label">CAPTCHA</label>

                <div className="d-flex align-items-center mb-2">
                  <div className="bg-light border rounded px-3 py-2 me-2 fw-bold fs-4 font-monospace">
                    {captcha}
                  </div>
                  <button
                    type="button"
                    className="btn btn-outline-secondary btn-sm"
                    onClick={refreshCaptcha}
                  >
                    ↻ Refresh
                  </button>
                </div>

                <input
                  type="text"
                  className="form-control"
                  value={userCaptcha}
                  onChange={(e) => setUserCaptcha(e.target.value)}
                />

                {captchaError && (
                  <div className="form-text text-danger">{captchaError}</div>
                )}
              </div>

              <div className="form-check mb-3">
                <input
                  type="checkbox"
                  className="form-check-input border border-success"
                  id="rememberMe"
                  checked={rememberMe}
                  onChange={(e) => setRememberMe(e.target.checked)}
                  required={true}
                />  
                <label className="form-check-label" htmlFor="rememberMe">
                  By clicking here, you are accepting our<a className="text-success"> Privacy policy, Terms & Conditions</a>
                </label>
              </div>

              <button
                type="submit"
                className="btn btn-success text-light w-100"
              >
                SignUp
              </button>
              <p className="text-success text-center mt-3">Already have an account? <a href="/vendor_login">Log In</a></p>
            </form>
          </div>
        </div>
      </div>
    </div>
    </div>
    </div>
   
    </div>
  )
}

export default Vendor_registration
